sections.code_example:
students = [
    {"name": "Alice", "grade": 92},
    {"name": "Bob",   "grade": 85},
    {"name": "Carol", "grade": 97}
]

# Access first student's name
print(students[0]["name"])

# Print all students
for student in students:
    print(student["name"], "-", student["grade"])

inventory = {
    "fruits":  ["apple", "banana", "cherry"],
    "veggies": ["carrot", "broccoli"],
    "grains":  ["rice", "oats"]
}

# Access second fruit
print(inventory["fruits"][1])

# Count items in each category
for category, items in inventory.items():
    print(category, ":", len(items), "items")

