exercises.solution:
books = [
    {"title": "Python Basics", "pages": 200},
    {"title": "Data Science 101", "pages": 350},
    {"title": "Web Dev Guide", "pages": 280}
]

for book in books:
    print(f"{book['title']}: {book['pages']} pages")

grid = [[10, 20], [30, 40]]

total = 0
for row in grid:
    for num in row:
        total += num
print(total)
